import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import { getProductById } from '../fetcher';
import styled from 'styled-components';

const ProductDetail = () => {
  const [product,setProduct] = useState({errorMessage:'',data:{}});
  const {productId}=useParams();

  useEffect(()=> {
    const fetchData = async() => {
      const responseObject = await getProductById(productId);
      setProduct(responseObject); 
    }
    fetchData();
  },[productId]);

  const createMarkup = () => {
    return { __html: product.data?.description}
  }

  return (
    <article>
        <ProductTitle>
          {product.data.title}
        </ProductTitle>
        <figure>
          <ProductImageContainer>
            <ProductImageContainerImage src={`/assets/${product.data.image}`} alt={product.data.title}>
            </ProductImageContainerImage>
          </ProductImageContainer>
        </figure>

        <aside>
        <ProductInfo>
            <h3>Dimensions</h3>
            <label>{product.data.specs?.dimensions}</label>
          </ProductInfo>
          {product.data.specs?.capacity &&
          <ProductInfo>
          <ProductInfoHeader><h3>Capacity</h3></ProductInfoHeader>
          <label>{product.data.specs?.capacity}</label>
          </ProductInfo>
          }
          <ProductInfo>
            <ProductInfoHeader>Features</ProductInfoHeader>
            <ul>
              {product.data.features?.map((f,i) =>{
                return<ProductInfoLI key={`feature${i}`}>{f}</ProductInfoLI>
              })}
            </ul>
            </ProductInfo>
        </aside>
        <aside>
          <ProductFP>
            &pound;{product.data.price};
          </ProductFP>
          <ProductInfoStock>
            <ProductInfoStockLabel>Stock Level:{product.data.stock}</ProductInfoStockLabel>
            <ProductInfoStockLabel>FREE Delivery</ProductInfoStockLabel>
          </ProductInfoStock>
          <ProductAction>
            <ProductActionButton>Add to Basket</ProductActionButton>
            </ProductAction>



        </aside>
        <ProductDescription dangerouslySetInnerHTML={createMarkup()}></ProductDescription>
    </article>
  );
};
const ProductDescription = styled.div `
  grid-column: 1/span 3;
`;
const ProductTitle = styled.div`
grid-column: 1/span 3;
color: darkslategray;
font-weight: bold;
font-size: 1.5em;
padding-left:10px ;
`;

const ProductImageContainer = styled.div`
  padding: 10px;
  width: 60%;
`;

const ProductImageContainerImage= styled.img`
  width: 100%;
  height: 100%;
`;

const ProductInfo = styled.div`
  display: flex;
  flex-direction: column;
`;

const ProductInfoHeader = styled.h3 `
color: darkslategray;
  font-size: 1em;
  font-weight: bold;
  padding-top: 10px;
  padding-bottom: 5px;
`;

const ProductInfoLI = styled.li `
padding-top: 5px;
`;

const ProductFP = styled.div`
  color: darkslategray;
  font-size: 2em;
  font-weight: bold;
  padding-top: 10px;
`;

const ProductInfoStock = styled.div`
padding-left: 10px;
margin-top: 20px;
padding-top: 10px;
background-color: white;
height: 25%;
width: 40%;
border-radius: 5px;
font-weight: bold;
flex-direction: column;
`;

const ProductInfoStockLabel = styled.label`
padding-bottom: 5px;
display: block;
color:  #007185;
`;


const ProductAction = styled.div`
display:flex;
flex-direction: column;
`;

const ProductActionButton = styled.button`
  width: 160px;
  height: 30px;
  border-radius: 10px;
  margin-top: 20px;
  background-color: #e47911;
  border: solid 1px slategrey;
  font-weight: bold;
`;
export default ProductDetail;
